def count_trailing_zeros(n: int) -> int:
    if n == 0:
        return 1  # The binary representation of 0 is '0', which has one trailing zero.
                  # Some definitions might return 0 or the bit-width of the integer type.
                  # This is a common interpretation for its string representation.

    count = 0
    while (n & 1) == 0:
        n >>= 1
        count += 1
    return count
